+// ─── Room lighting ─────────────────────────────────────────────────
+
+function drawRoomLighting(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number) {
+  const cs = Math.max(w, h) * 0.4;
+  for (const [cx, cy] of [[x, y], [x + w, y], [x, y + h], [x + w, y + h]] as [number, number][]) {
+    const g = ctx.createRadialGradient(cx, cy, 0, cx, cy, cs);
+    g.addColorStop(0, 'rgba(0,0,0,0.2)'); g.addColorStop(1, 'rgba(0,0,0,0)');
+    ctx.fillStyle = g;
+    ctx.fillRect(Math.max(x, cx - cs), Math.max(y, cy - cs), cs, cs);
+  }
+  if (type === 'healer' || type === 'king') {
+    const g = ctx.createRadialGradient(x + w / 2, y + h * 0.5, 0, x + w / 2, y + h * 0.5, w * 0.45);
+    g.addColorStop(0, 'rgba(255, 200, 100, 0.04)'); g.addColorStop(1, 'rgba(255, 200, 100, 0)');
+    ctx.fillStyle = g; ctx.fillRect(x, y, w, h);
+  }
+}
+
+// ─── Ambient particles ─────────────────────────────────────────────
+
+interface Particle {
+  x: number;
+  y: number;
+  vx: number;
+  vy: number;
+  lifespan: number;
+  age: number;
+  color: string;
+  size: number;
+}
+
+const roomParticlesMap: Map<string, Particle[]> = new Map();
+
+function randomRange(min: number, max: number) {
+  return Math.random() * (max - min) + min;
+}
+
+function drawRoomParticles(ctx: CanvasRenderingContext2D, roomType: CharacterType, bounds: {x: number, y: number, w: number, h: number}, frame: number) {
+  const {x, y, w, h} = bounds;
+  if (!roomParticlesMap.has(roomType)) {
+    roomParticlesMap.set(roomType, []);
+  }
+  const particles = roomParticlesMap.get(roomType)!;
+
+  // Spawn new particles based on room type and frame
+  switch (roomType) {
+    case 'blacksmith': // Workshop - orange forge sparks rising and fading
+      if (frame % 10 === 0 && particles.length < 30) {
+        particles.push({
+          x: x + randomRange(w * 0.1, w * 0.3),
+          y: y + randomRange(h * 0.7, h * 0.9),
+          vx: randomRange(-0.3, 0.3),
+          vy: randomRange(-1.2, -0.6),
+          lifespan: randomRange(30, 50),
+          age: 0,
+          color: 'rgba(240,160,48,0.8)',
+          size: 2
+        });
+      }
+      break;
+    case 'healer': // Healing Chamber - green healing sparkles floating upward
+      if (frame % 15 === 0 && particles.length < 25) {
+        particles.push({
+          x: x + randomRange(w * 0.4, w * 0.7),
+          y: y + randomRange(h * 0.6, h * 0.9),
+          vx: randomRange(-0.1, 0.1),
+          vy: randomRange(-0.4, -0.1),
+          lifespan: randomRange(40, 60),
+          age: 0,
+          color: 'rgba(64,224,128,0.7)',
+          size: 1.5
+        });
+      }
+      break;
+    case 'scribe': // Library - dust motes drifting slowly
+      if (frame % 20 === 0 && particles.length < 20) {
+        particles.push({
+          x: x + randomRange(0, w),
+          y: y + randomRange(0, h),
+          vx: randomRange(-0.05, 0.05),
+          vy: randomRange(-0.02, 0.02),
+          lifespan: randomRange(70, 100),
+          age: 0,
+          color: 'rgba(138,122,90,0.5)',
+          size: 1
+        });
+      }
+      break;
+    case 'dungeon': // Dungeon - dripping water droplets falling
+      if (frame % 12 === 0 && particles.length < 25) {
+        particles.push({
+          x: x + randomRange(w * 0.3, w * 0.7),
+          y: y + randomRange(0, h * 0.3),
+          vx: 0,
+          vy: randomRange(0.8, 1.2),
+          lifespan: randomRange(40, 60),
+          age: 0,
+          color: 'rgba(100,150,200,0.7)',
+          size: 2
+        });
+      }
+      break;
+    case 'sentinel': // Watchtower - wind streaks
+      if (frame % 8 === 0 && particles.length < 30) {
+        particles.push({
+          x: x + randomRange(0, w),
+          y: y + randomRange(0, h),
+          vx: randomRange(0.8, 1.5),
+          vy: randomRange(-0.1, 0.1),
+          lifespan: randomRange(20, 40),
+          age: 0,
+          color: 'rgba(255,255,255,0.3)',
+          size: 2
+        });
+      }
+      break;
+  }
+
+  // Update and draw particles
+  for (let i = particles.length - 1; i >= 0; i--) {
+    const p = particles[i];
+    p.x += p.vx;
+    p.y += p.vy;
+    p.age++;
+    if (p.age >= p.lifespan) {
+      particles.splice(i, 1);
+      continue;
+    }
+    // Fade out alpha based on age
+    const alpha = (1 - p.age / p.lifespan) * parseFloat(p.color.slice(p.color.indexOf(',') + 1, p.color.lastIndexOf(')')));
+    const baseColor = p.color.substring(0, p.color.indexOf('('));
+    // Extract rgb from rgba string
+    const rgbaMatch = p.color.match(/rgba?\((\d+),\s*(\d+),\s*(\d+),?\s*([\d\.]+)?\)/);
+    if (!rgbaMatch) continue;
+    const r = rgbaMatch[1], g = rgbaMatch[2], b = rgbaMatch[3];
+    ctx.fillStyle = `rgba(${r},${g},${b},${alpha.toFixed(3)})`;
+    ctx.beginPath();
+    ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
+    ctx.fill();
+  }
+}
+
+function spawnRoomParticles(type: CharacterType, rid: string, x: number, y: number, w: number, h: number, frame: number) {
+  if (frame % 8 !== 0) return;
+  switch (type) {
+    case 'blacksmith':
+      if (frame % 12 === 0) {
+        spawnParticle(rid, x + w * 0.15, y + h * 0.25, '#f0a030', (Math.random() - 0.5) * 1.5, -1.5, 2, 30);
+        spawnParticle(rid, x + w * 0.18, y + h * 0.28, '#e06020', (Math.random() - 0.5), -1, 1.5, 25);
+      }
+      break;
+    case 'healer':
+      if (frame % 16 === 0) {
+        const a = Math.random() * Math.PI * 2, r = Math.min(w, h) * 0.15;
+        spawnParticle(rid, x + w * 0.55 + Math.cos(a) * r, y + h * 0.68 + Math.sin(a) * r, '#40e080', 0, -0.3, 2, 50);
+      }
+      break;
+    case 'scribe':
+      if (frame % 24 === 0) spawnParticle(rid, x + Math.random() * w, y + h * 0.4, '#8a7a5a', 0.1, -0.1, 1, 80);
+      break;
+    case 'king':
+      if (frame % 32 === 0) spawnParticle(rid, x + w * 0.5 + (Math.random() - 0.5) * 30, y + h * 0.3, P.gold[4], 0, -0.2, 2, 40);
+      break;
+    case 'sentinel':
+      if (frame % 20 === 0) {
+        spawnParticle(rid, x + w * 0.25 + Math.random() * w * 0.5, y + h * 0.04 + Math.random() * h * 0.25, '#ffffff', 0, 0, 1.5, 20);
+      }
+      break;
+  }
+}
+
+// Re-export movement helpers for agents.tsx
+export { getCS, updateMovement, drawRoomParticles };
